// On récupère le sujet et le corps texte du mail d'alerte.
// Selon la source, le corps peut être dans `text`, `snippet` ou `html`.
const subject = $json.subject || '';
const body = $json.text || $json.snippet || $json.html || '';

// Prompt d'extraction : on demande explicitement un JSON strict, sans texte autour.
const prompt = `Tu es un assistant qui extrait les informations d'une offre d'emploi à partir d'un e-mail d'alerte.
À partir du sujet et du corps ci-dessous, renvoie UNIQUEMENT un objet JSON valide, sans aucun texte autour, avec ces clés :
- "intitule" : l'intitulé du poste (string)
- "entreprise" : le nom de l'entreprise (string, "" si absent)
- "lieu" : la ville ou la région (string, "" si absent)
- "lien" : l'URL directe vers l'offre (string, "" si absent)

Sujet : ${subject}

Corps :
${body}`;

// Corps de la requête envoyée à l'API Gemini.
// responseSchema force un retour JSON structuré et fiable.
const geminiBody = {
  contents: [{ parts: [{ text: prompt }] }],
  generationConfig: {
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'OBJECT',
      properties: {
        intitule: { type: 'STRING' },
        entreprise: { type: 'STRING' },
        lieu: { type: 'STRING' },
        lien: { type: 'STRING' }
      },
      required: ['intitule']
    }
  }
};

return { geminiBody };

// --- Structuration tolérante aux pannes ---
// Gemini renvoie normalement le JSON dans candidates[0].content.parts[].text
const parts = $json?.candidates?.[0]?.content?.parts || [];
let raw = parts.map(p => p.text || '').join('').trim();

// Nettoyage : Gemini entoure parfois le JSON de ```json ... ```
raw = raw.replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();

// Parse tolérant : si le JSON est illisible, on ne casse pas le flux.
let offre = {};
try {
  offre = JSON.parse(raw);
} catch (e) {
  offre = {};
}

// On récupère le mail d'origine pour compléter d'éventuels champs manquants.
let email = {};
try { email = $('Gmail - Alerte Emploi').item.json; } catch (e) { email = {}; }
const emailText = [email.text, email.html, email.snippet, email.subject].filter(Boolean).join('\n');

// Normalise une URL : renvoie une vraie http(s) ou null (jamais "").
function cleanUrl(u) {
  if (typeof u === 'string') {
    const m = u.match(/https?:\/\/[^\s"'<>()]+/i);
    if (m) return m[0];
  }
  return null;
}

// Lien : celui de Gemini, sinon le 1er lien trouvé dans le mail, sinon null.
let lien = cleanUrl(offre.lien);
if (!lien) lien = cleanUrl(emailText);

// Intitulé : celui de Gemini, sinon le sujet du mail, sinon un libellé de secours.
const intitule = (offre.intitule || email.subject || 'Offre sans intitulé').toString().trim();

return {
  intitule,
  entreprise: (offre.entreprise || '').toString().trim(),
  lieu: (offre.lieu || '').toString().trim(),
  lien: lien,            // null si aucun lien valide -> accepté par Notion
  recupere_le: new Date().toISOString()
};

// Déduplication persistée entre exécutions.
// On mémorise les liens (ou intitulés) déjà traités dans le stockage statique du workflow.
// Les offres déjà vues sont écartées ; seules les nouvelles passent à la suite.
const staticData = $getWorkflowStaticData('global');
staticData.seen = staticData.seen || [];

const nouvelles = [];
for (const item of $input.all()) {
  const cle = item.json.lien || item.json.intitule;
  if (!cle) { continue; }
  if (!staticData.seen.includes(cle)) {
    staticData.seen.push(cle);
    nouvelles.push(item);
  }
}

// Optionnel : on borne l'historique pour éviter qu'il grossisse indéfiniment.
if (staticData.seen.length > 5000) {
  staticData.seen = staticData.seen.slice(-5000);
}

return nouvelles;
